from collections import Counter

class Solution:
    def leastInterval(self, tasks, n):
        counts = Counter(tasks).values()
        most = max(counts)
        tied = sum(1 for count in counts if count == most)
        return max(len(tasks), (most - 1) * (n + 1) + tied)
```

